#!/usr/bin/env node
// Code generated by AI (claude-sonnet-5)

'use strict'

const fs = require('node:fs')
const path = require('node:path')

// pluginRoot mirrors the ${PLUGIN_ROOT:-${CLAUDE_PLUGIN_ROOT}} fallback used in hooks.json:
// PLUGIN_ROOT is the workaround while CLAUDE_PLUGIN_ROOT isn't correctly valorized in VSCode.
const pluginRoot = () => process.env.PLUGIN_ROOT || process.env.CLAUDE_PLUGIN_ROOT

const main = () => {
    const rulesPath = path.join(pluginRoot(), 'rules', 'caveman-activate.md')
    let additionalContext = fs.readFileSync(rulesPath, 'utf8').trim()

    const level = (process.env.CAVEMAN_LEVEL ?? '').trim()
    if (level) {
        additionalContext += `\n\nActive level: ${level}`
    }

    // merges Claude/Codex's hookSpecificOutput wrapper with Copilot's flat shape, so the same
    // script and payload work as a SessionStart hook across all three agents.
    const body = JSON.stringify({
        hookSpecificOutput: {
            hookEventName: 'SessionStart',
            additionalContext,
        },
        additionalContext,
    })
    process.stdout.write(body)
}

main()
